// Off-hours check (NYC time). During business hours we forward to a real human.
const TIMEZONE = 'America/New_York';
const BUSINESS_HOURS = {
  1: { open: 9, close: 18 }, 2: { open: 9, close: 18 }, 3: { open: 9, close: 18 },
  4: { open: 9, close: 18 }, 5: { open: 9, close: 18 }, 6: { open: 10, close: 16 }
};
const LIVE_AGENT_NUMBER = $env.LIVE_AGENT_NUMBER || '';

const now = new Date(new Date().toLocaleString('en-US', { timeZone: TIMEZONE }));
const day = now.getDay();
const hour = now.getHours();
const window = BUSINESS_HOURS[day];
const isBusinessHours = !!window && hour >= window.open && hour < window.close;
const body = $input.first().json.body || $input.first().json;

return [{ json: {
  isBusinessHours, isOffHours: !isBusinessHours, liveAgentNumber: LIVE_AGENT_NUMBER,
  callSid: body.CallSid || null, fromNumber: body.From || null, toNumber: body.To || null
}}];

const liveNumber = $json.liveAgentNumber;
const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Joanna-Neural">Connecting you to our team. Please hold.</Say>
  <Dial timeout="25" callerId="${$json.toNumber || ''}">${liveNumber}</Dial>
</Response>`;
return [{ json: { twiml } }];

// Extract the array of rewritten search queries from the LLM output, then
// always append the caller's literal transcript as a final variant. The literal
// variant guarantees FTS gets a shot at exact-phrase matching even if the
// rewriter strips a distinguishing word — at the cost of one extra RPC call.
const out = $input.first().json;
const literalTranscript = ($('Extract Speech Fields').first().json.transcript || '').trim();
const fallback = literalTranscript || 'general inquiry';

function getText(j) {
  if (!j) return null;
  if (typeof j.output_text === 'string') return j.output_text;
  if (typeof j.text === 'string') return j.text;
  if (typeof j.content === 'string') return j.content;
  if (typeof j.message?.content === 'string') return j.message.content;
  if (Array.isArray(j.output)) {
    for (const item of j.output) {
      if (Array.isArray(item?.content)) {
        for (const c of item.content) {
          if (typeof c?.text === 'string') return c.text;
        }
      }
    }
  }
  if (typeof j.choices?.[0]?.message?.content === 'string') return j.choices[0].message.content;
  return null;
}

function tryParse(s) {
  if (typeof s !== 'string') return null;
  const cleaned = s.trim().replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '').trim();
  try { return JSON.parse(cleaned); } catch { return null; }
}

function normalizeRewritten(value) {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') return [value];
  return [];
}

let rewritten = [];
if (out) {
  if (Array.isArray(out.rewritten) || typeof out.rewritten === 'string') {
    rewritten = normalizeRewritten(out.rewritten);
  } else {
    const parsed = tryParse(getText(out));
    if (parsed && (Array.isArray(parsed.rewritten) || typeof parsed.rewritten === 'string')) {
      rewritten = normalizeRewritten(parsed.rewritten);
    }
  }
}

rewritten = rewritten
  .map(s => (typeof s === 'string' ? s.trim() : ''))
  .filter(Boolean);

// Always include the caller's literal transcript so FTS sees exact tokens —
// rewriters tend to strip identifying-but-uncommon words like product names.
if (literalTranscript) rewritten.push(literalTranscript);

// Dedupe (case-insensitive) while preserving order.
const seen = new Set();
rewritten = rewritten.filter(q => {
  const k = q.toLowerCase();
  if (seen.has(k)) return false;
  seen.add(k);
  return true;
});

if (rewritten.length === 0) rewritten = [fallback];

return [{ json: { rewritten, variantCount: rewritten.length, literalIncluded: !!literalTranscript } }];

// Fan out one item per (query, embedding) pair. The downstream HTTP node will
// make one RPC call per item; Fuse Retrievals collects all responses via
// $input.all() and does the RRF merge.
const queries = $('Extract Rewritten').first().json?.rewritten;
const queriesArr = Array.isArray(queries)
  ? queries.filter(s => typeof s === 'string' && s.trim().length > 0)
  : (typeof queries === 'string' && queries.trim() ? [queries] : []);

const embRaw = $input.first().json || {};
const embData = Array.isArray(embRaw.data) ? embRaw.data : [];

const cfg = $('RAG Config').first().json || {};
const matchCount = Number(cfg.topK) || 8;

const items = [];
for (let i = 0; i < Math.min(queriesArr.length, embData.length); i++) {
  const e = embData[i] && embData[i].embedding;
  if (Array.isArray(e) && e.length > 0) {
    items.push({
      json: {
        variantIndex: i,
        query: queriesArr[i],
        embedding: e,
        matchCount
      }
    });
  }
}

// If nothing valid, emit a placeholder so the chain still flows. The HTTP
// node will likely 4xx (empty embedding) and Fuse Retrievals handles that.
if (items.length === 0) {
  items.push({
    json: {
      variantIndex: 0,
      query: $('Extract Speech Fields').first().json?.transcript || 'general inquiry',
      embedding: [],
      matchCount,
      placeholder: true
    }
  });
}

return items;

// Reciprocal Rank Fusion across N variant retrievals, with a follow-up boost
// AND a pinned-source fallback.
//
// (a) RRF: n8n's HTTP node v4.2 splits an array response into one item per
// element, and the resulting `pairedItem` carries a unique global index
// (0..N*matchCount-1) instead of pointing back to the originating variant.
// Trusting it collapses every row into its own variant bucket, all at rank 1
// — degenerating the RRF into "count of variants the row appears in × const".
// Instead, we trust item ORDER (which n8n preserves) and group by
// floor(idx / matchCount).
//
// (b) Anchored follow-up boost (token-overlap, full-history): when ANY URL
// previously cited in the conversation has a slug sharing >=2 tokens with the
// rewriter variants — at least one of which is non-domain (i.e., not
// "marble"/"tub"/etc) — multiply fused_score by ANCHOR_BOOST for chunks whose
// source_url matches that URL. We scan the FULL conversation history (via
// Format History's allPriorSources), so a topic-back-switch (caller diverted
// to Calacatta then returned to the original Designer Bathtub) still anchors
// to the original product. The older substring-match was both too strict
// (long marketing slugs almost never appear verbatim in a rewriter variant)
// and too narrow (only looked at the most recent turn's sources).
//
// (c) Pinned-source fallback: for each URL whose slug matched the anchor
// detector in (b), fetch its chunks directly via PostgREST and inject them
// into the fused pool with a high score. Guarantees the matched product is a
// top candidate even if the rewriter+RRF didn't surface it.
const RRF_K = 60;
const ANCHOR_BOOST = 2.0;
const matchCount = Number($('RAG Config').first().json?.topK) || 8;
const allItems = $input.all();

const byVariant = new Map();
allItems.forEach((item, idx) => {
  const j = item?.json;
  if (!j) return;
  const vi = Math.floor(idx / matchCount);
  let rows = [];
  if (Array.isArray(j)) rows = j;
  else if (Array.isArray(j.body)) rows = j.body;
  else if (Array.isArray(j.data)) rows = j.data;
  else if (j.id !== undefined && j.content !== undefined) rows = [j];
  if (rows.length === 0) return;
  if (!byVariant.has(vi)) byVariant.set(vi, []);
  byVariant.get(vi).push(...rows);
});

const fused = new Map();
const callDiagnostics = [];
for (const [vi, rows] of byVariant) {
  callDiagnostics.push({ vi, ok: true, rowCount: rows.length });
  rows.forEach((row, idx) => {
    const rank = idx + 1;
    const score = 1.0 / (RRF_K + rank);
    const existing = fused.get(row.id);
    if (existing) {
      existing.fused_score += score;
      existing.variant_hits.push(vi);
      if (typeof row.semantic_rank === 'number' &&
          (existing.best_semantic_rank == null || row.semantic_rank < existing.best_semantic_rank)) {
        existing.best_semantic_rank = row.semantic_rank;
      }
      if (typeof row.fts_rank === 'number' &&
          (existing.best_fts_rank == null || row.fts_rank < existing.best_fts_rank)) {
        existing.best_fts_rank = row.fts_rank;
      }
    } else {
      fused.set(row.id, {
        ...row,
        fused_score: score,
        variant_hits: [vi],
        best_semantic_rank: typeof row.semantic_rank === 'number' ? row.semantic_rank : null,
        best_fts_rank: typeof row.fts_rank === 'number' ? row.fts_rank : null
      });
    }
  });
}

let priorSources = [];
let allPriorSources = [];
let rewritten = [];
try {
  const fh = $('Format History').first().json || {};
  priorSources = fh.priorSources || [];
  // Fall back to priorSources if Format History hasn't been updated yet.
  allPriorSources = (Array.isArray(fh.allPriorSources) && fh.allPriorSources.length)
    ? fh.allPriorSources
    : priorSources;
} catch (e) {}
try { rewritten = $('Extract Rewritten').first().json.rewritten || []; } catch (e) {}

function slugFromUrl(u) {
  if (typeof u !== 'string') return '';
  const m = u.match(/\/(?:products|collections)\/([^\/?#]+)/i);
  if (!m) return '';
  return m[1].replace(/-/g, ' ').toLowerCase();
}

const STOP = new Set([
  'the','a','an','of','for','to','in','on','at','by','with','and','or','from',
  'is','are','was','were','be','have','has','had','do','does','it','this','that',
  'sale','new','about','how','what','which','when','where','who','why'
]);
// Domain stopwords: tokens that appear in nearly every catalog slug, so
// overlap on these alone is not signal that the user is anchoring on the
// prior product. At least one non-domain overlap token is required.
const DOMAIN = new Set(['marble','tub','bathtub','stone','product','collection']);
function tokensOf(s) {
  return String(s || '').toLowerCase()
    .replace(/[^a-z0-9 ]+/g, ' ')
    .split(/\s+/)
    .filter(t => t.length > 2 && !STOP.has(t));
}

const variantTokens = new Set();
for (const v of rewritten) for (const t of tokensOf(v)) variantTokens.add(t);

const ANCHOR_TOKEN_THRESHOLD = 2;
// Of all prior URLs across the whole conversation, keep only those whose slug
// has token-overlap with the current rewriter variants. In a topic switch the
// list is empty (no overlap); in a topic-back-switch only the URL the caller
// is naming again survives.
const matchedAnchors = [];
for (const url of allPriorSources) {
  const slug = slugFromUrl(url);
  if (!slug) continue;
  const overlap = tokensOf(slug).filter(t => variantTokens.has(t));
  if (overlap.length < ANCHOR_TOKEN_THRESHOLD) continue;
  if (!overlap.some(t => !DOMAIN.has(t))) continue;
  matchedAnchors.push(url);
}
const anchoredToPrior = matchedAnchors.length > 0;
const matchedUrlSet = new Set(matchedAnchors);

let boostedCount = 0;
if (anchoredToPrior) {
  for (const row of fused.values()) {
    const url = row.metadata && row.metadata.source_url;
    if (url && matchedUrlSet.has(url)) {
      row.fused_score *= ANCHOR_BOOST;
      row.anchor_boosted = true;
      boostedCount++;
    }
  }
}

// Pinned-source fallback: fetch chunks for the matched URLs directly so
// they're guaranteed top candidates, in case the rewriter+RRF didn't surface
// them.
let pinnedAdded = 0;
let pinError = null;
// Skip pin fetch if every matchedAnchor URL is already represented in the fused
// pool's top-N candidates — saves a 200-500ms PostgREST GET on the response path.
const PIN_TOPN_CHECK = matchCount * 2;
let needPinFetch = anchoredToPrior && matchedAnchors.length > 0;
if (needPinFetch) {
  const topRows = Array.from(fused.values())
    .sort((a, b) => b.fused_score - a.fused_score)
    .slice(0, PIN_TOPN_CHECK);
  const presentUrls = new Set();
  for (const r of topRows) {
    const u = r && r.metadata && r.metadata.source_url;
    if (u) presentUrls.add(u);
  }
  if (matchedAnchors.every(u => presentUrls.has(u))) {
    needPinFetch = false;
  }
}
if (needPinFetch) {
  let helpers = null;
  try { if (this && this.helpers) helpers = this.helpers; } catch (e) {}
  const cfg2 = $('RAG Config').first().json || {};
  const baseUrl = cfg2.supabaseUrl;
  const apiKey = cfg2.serviceRoleKey;
  if (helpers && typeof helpers.httpRequest === 'function' && baseUrl && apiKey) {
    const inList = matchedAnchors.map(u => '"' + u + '"').join(',');
    const valuePart = 'in.(' + inList + ')';
    const url = baseUrl + '/rest/v1/marblebee_documents'
      + '?select=id,content,metadata,source_url,chunk_index'
      + '&source_url=' + encodeURIComponent(valuePart)
      + '&order=chunk_index.asc'
      + '&limit=' + (matchedAnchors.length * 3);
    try {
      const rows = await helpers.httpRequest({
        method: 'GET',
        url: url,
        headers: {
          apikey: apiKey,
          Authorization: 'Bearer ' + apiKey,
          Accept: 'application/json'
        },
        json: true,
        returnFullResponse: false,
        timeout: 3000,
      });
      if (Array.isArray(rows)) {
        let maxExisting = 0;
        for (const r of fused.values()) if (r.fused_score > maxExisting) maxExisting = r.fused_score;
        const PIN_BASE = (maxExisting || 0.05) * 1.5;
        rows.forEach((row, idx) => {
          if (fused.has(row.id)) {
            const existing = fused.get(row.id);
            existing.fused_score = Math.max(existing.fused_score, PIN_BASE - idx * 0.0001);
            existing.pinned = true;
          } else {
            fused.set(row.id, {
              ...row,
              fused_score: PIN_BASE - idx * 0.0001,
              variant_hits: [],
              best_semantic_rank: null,
              best_fts_rank: null,
              pinned: true
            });
          }
          pinnedAdded++;
        });
      }
    } catch (e) {
      pinError = String(e && e.message || e);
    }
  }
}

const variantsUsed = byVariant.size;
const merged = Array.from(fused.values())
  .sort((a, b) => b.fused_score - a.fused_score)
  .slice(0, matchCount * Math.max(variantsUsed, 1));

return [{
  json: {
    body: merged,
    retrievedCount: merged.length,
    variantsUsed,
    inputItemsCount: allItems.length,
    anchoredToPrior,
    boostedCount,
    pinnedAdded,
    pinError,
    matchedAnchors,
    priorSources,
    allPriorSources,
    callDiagnostics
  }
}];

// Diversify retrievals: keep at most N chunks per source_url so we don't
// give the LLM five chunks all from one product page.
const MAX_PER_SOURCE = $('RAG Config').first().json.maxChunksPerSource || 2;

const raw = $input.first().json;
let rows = [];
if (Array.isArray(raw)) rows = raw;
else if (Array.isArray(raw.body)) rows = raw.body;
else if (Array.isArray(raw.data)) rows = raw.data;
// Supabase REST returns the array at top level when calling RPC
else if (raw && typeof raw === 'object' && raw.id !== undefined && raw.content !== undefined) rows = [raw];
else if (Array.isArray(raw?.json)) rows = raw.json;

const counts = new Map();
const kept = [];
const dropped = [];

for (const r of rows) {
  const url = (r.metadata && r.metadata.source_url) || 'unknown';
  const seen = counts.get(url) || 0;
  if (seen < MAX_PER_SOURCE) {
    kept.push(r);
    counts.set(url, seen + 1);
  } else {
    dropped.push({ url, similarity: r.similarity });
  }
}

return [{
  json: {
    chunks: kept,
    droppedForDiversity: dropped,
    retrievedCount: rows.length,
    keptCount: kept.length,
    distinctSources: counts.size
  }
}];

// Build a numbered context block the LLM can cite. Each chunk gets a number
// and the source URL is preserved. Individual chunks are capped so a single
// fat chunk can't crowd everything else out, and the total is capped so the
// prompt stays comfortably inside gpt-4o-mini's window.
const chunks = $json.chunks || [];
const MAX_CONTEXT_CHARS = 4500;
const MAX_PER_CHUNK_CHARS = 900;

const formatted = [];
let total = 0;
let sourceUrls = [];

for (let i = 0; i < chunks.length; i++) {
  const c = chunks[i];
  const url = (c.metadata && c.metadata.source_url) || 'unknown';
  const title = (c.metadata && c.metadata.page_title) || '';
  let content = (c.content || '').trim();
  if (content.length > MAX_PER_CHUNK_CHARS) {
    content = content.slice(0, MAX_PER_CHUNK_CHARS) + '…';
  }
  const block = `[${i + 1}] (${title || url}) ${url}\n${content}`;
  if (total + block.length > MAX_CONTEXT_CHARS && formatted.length > 0) break;
  formatted.push(block);
  if (!sourceUrls.includes(url)) sourceUrls.push(url);
  total += block.length;
}

const contextBlock = formatted.join('\n\n---\n\n');
return [{
  json: {
    contextBlock: contextBlock || '(no relevant content found in the knowledge base)',
    chunksUsed: formatted.length,
    sourceUrls,
    chunks  // keep for logging
  }
}];

// Parse the OpenAI JSON response, enforce confidence floor, attach context.
// Tolerant of:
//   1) Every shape the OpenAI / langchain nodes have emitted (Responses API,
//      chat-completions, simplified, already-parsed)
//   2) Common LLM JSON-format errors — specifically the case where string values
//      are missing the opening double quote: "key": value with spaces",
const out = $input.first().json;

function getText(j) {
  if (!j) return null;
  if (typeof j.output_text === 'string') return j.output_text;
  if (typeof j.text === 'string') return j.text;
  if (typeof j.content === 'string') return j.content;
  if (typeof j.message?.content === 'string') return j.message.content;
  if (Array.isArray(j.output)) {
    for (const item of j.output) {
      if (Array.isArray(item?.content)) {
        for (const c of item.content) {
          if (typeof c?.text === 'string') return c.text;
        }
      }
    }
  }
  if (typeof j.choices?.[0]?.message?.content === 'string') return j.choices[0].message.content;
  return null;
}

function stripFences(s) {
  return s.trim().replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '').trim();
}

// Repair LLM JSON: add missing opening quotes on string values.
// Pattern: "key":<space><non-quote-char><...rest of line...>",
//          → "key":<space>"<...>"
function repairUnquotedStrings(s) {
  return s.replace(
    /("[A-Za-z_][\w]*"\s*:\s*)([^"\[\{\d\-tfn\s][^\n]*?)("\s*[,\n}])/g,
    (m, key, value, end) => key + '"' + value + end
  ).replace(
    // Same pattern but trailing close-brace without preceding quote (last field)
    /("[A-Za-z_][\w]*"\s*:\s*)([^"\[\{\d\-tfn\s][^\n]*?)(\n\s*})/g,
    (m, key, value, end) => key + '"' + value.replace(/\s*$/, '') + '"' + end
  );
}

function tryParseLenient(s) {
  if (typeof s !== 'string') return null;
  const cleaned = stripFences(s);
  try { return JSON.parse(cleaned); } catch {}
  try { return JSON.parse(repairUnquotedStrings(cleaned)); } catch {}
  return null;
}

// Last-resort regex extraction. Pulls each field individually.
function regexExtract(s) {
  if (typeof s !== 'string') return null;
  const grabStr = (key) => {
    // Match key: optional-quote value optional-quote (lookahead next field or close)
    const re = new RegExp(
      '"' + key + '"\\s*:\\s*"?([\\s\\S]+?)"?\\s*(?=,\\s*\\n\\s*"\\w+"|\\n?\\s*})',
      'i'
    );
    const m = s.match(re);
    return m ? m[1].trim().replace(/\s*"\s*$/, '') : undefined;
  };
  const intentM = s.match(/"intent"\s*:\s*"?(answered|escalate)"?/i);
  if (!intentM) return null;
  const confM = s.match(/"confidence"\s*:\s*([\d.]+)/);
  const sourcesM = s.match(/"sources"\s*:\s*\[([\s\S]*?)\]/);
  const sources = sourcesM
    ? Array.from(sourcesM[1].matchAll(/"([^"]+)"/g)).map(m => m[1])
    : [];
  return {
    intent: intentM[1].toLowerCase(),
    confidence: confM ? parseFloat(confM[1]) : 0,
    spoken_response: grabStr('spoken_response'),
    summary: grabStr('summary'),
    caller_question: grabStr('caller_question'),
    category: (grabStr('category') || 'other').toLowerCase(),
    sources,
    reasoning: grabStr('reasoning')
  };
}

let parsed = null;
let parseStrategy = 'none';

// Strategy A: top-level already an object with intent
if (out && typeof out.intent === 'string') {
  parsed = out;
  parseStrategy = 'top-level-object';
}
// Strategy B: message.content already an object
if (!parsed) {
  const m = out?.message?.content;
  if (m && typeof m === 'object' && typeof m.intent === 'string') {
    parsed = m;
    parseStrategy = 'message-object';
  }
}
// Strategy C: extract text and try to parse (with repair)
let rawText = null;
if (!parsed) {
  rawText = getText(out);
  parsed = tryParseLenient(rawText);
  if (parsed) parseStrategy = 'lenient-parse';
}
// Strategy D: regex extraction as last resort
if (!parsed && rawText) {
  parsed = regexExtract(rawText);
  if (parsed) parseStrategy = 'regex-extract';
}

if (!parsed || typeof parsed.intent !== 'string') {
  parsed = {
    intent: 'escalate',
    confidence: 0,
    spoken_response: 'I am having trouble looking that up right now. Let me have a team member call you back with the exact details.',
    summary: 'Failed to parse RAG response',
    caller_question: '',
    category: 'other',
    sources: [],
    reasoning: 'parse failure'
  };
  parseStrategy = 'fallback';
}

// Enforce 0.9 confidence floor regardless of model self-assessment.
const threshold = $('RAG Config').first().json.confidenceThreshold || 0.9;
const aiConfidence = typeof parsed.confidence === 'number' ? parsed.confidence : 0;
let enforcedIntent = parsed.intent;
if (parsed.intent === 'answered' && aiConfidence < threshold) {
  enforcedIntent = 'escalate';
  parsed.spoken_response = 'I want to make sure you get the most accurate information. Let me have a team member follow up with you on this number shortly.';
}

const caller = $('Extract Speech Fields').first().json;
const ctx = $('Build Context').first().json;
const startedAt = caller.startedAt;
const responseMs = startedAt ? Date.now() - new Date(startedAt).getTime() : null;

return [{
  json: {
    intent: enforcedIntent,
    aiOriginalIntent: parsed.intent,
    aiConfidence,
    confidenceThreshold: threshold,
    parseStrategy,
    spokenResponse: parsed.spoken_response,
    summary: parsed.summary,
    callerQuestion: parsed.caller_question || caller.transcript,
    category: parsed.category,
    sources: parsed.sources || [],
    reasoning: parsed.reasoning,
    callSid: caller.callSid,
    fromNumber: caller.fromNumber,
    transcript: caller.transcript,
    speechConfidence: caller.speechConfidence,
    chunksUsed: ctx?.chunksUsed || 0,
    retrievedChunks: ctx?.chunks || [],
    retrievedSourceUrls: ctx?.sourceUrls || [],
    responseMs
  }
}];

// Twilio call-status callback. Extract CallSid + status, then forward to the
// Redis delete node which removes the chat-history key for this session so
// memory is cleared the instant the call ends (TTL stays as a safety net).
const body = $input.first().json.body || $input.first().json;
const callSid = body.CallSid || body.callSid || null;
const callStatus = (body.CallStatus || body.callStatus || '').toLowerCase();
const terminalStatuses = ['completed', 'busy', 'no-answer', 'failed', 'canceled'];
return [{
  json: {
    callSid,
    callStatus,
    isTerminal: terminalStatuses.includes(callStatus),
    sessionKey: callSid,
    receivedAt: new Date().toISOString()
  }
}];

// Aggregate the Memory Manager's output into a single item that matches the
// shape the downstream prompts expect. Also parses the [sources: ...] suffix
// we append to AI messages, so the rewriter can anchor follow-ups to the
// canonical product/collection URLs cited in the previous assistant turn.
const items = $input.all();
const messages = [];

function parseSources(text) {
  if (typeof text !== 'string') return { text: text, urls: [] };
  const m = text.match(/\n?\[sources:\s*([^\]]*)\]\s*$/i);
  if (!m) return { text: text, urls: [] };
  const urls = m[1].split(',').map(s => s.trim()).filter(Boolean);
  const stripped = text.slice(0, m.index).replace(/\s+$/, '');
  return { text: stripped, urls: urls };
}

function pushMsg(m) {
  if (!m || typeof m !== 'object') return;
  const hasPair = (typeof m.human === 'string' && m.human) || (typeof m.ai === 'string' && m.ai);
  if (hasPair) {
    if (typeof m.human === 'string' && m.human) messages.push({ type: 'human', content: m.human });
    if (typeof m.ai === 'string' && m.ai) {
      const r = parseSources(m.ai);
      messages.push({ type: 'ai', content: r.text, sources: r.urls });
    }
    return;
  }
  const type = String(m.type || m.role || '').toLowerCase();
  const rawContent = m.content || m.message || m.text || '';
  if (!rawContent) return;
  if (type === 'ai' || type === 'assistant') {
    const r = parseSources(rawContent);
    messages.push({ type: type, content: r.text, sources: r.urls });
  } else {
    messages.push({ type: type, content: rawContent });
  }
}

if (items.length === 1) {
  const j0 = items[0]?.json || {};
  const arr = j0.messages || j0.chatMessages || j0.history;
  if (Array.isArray(arr)) {
    for (const m of arr) pushMsg(m);
  } else if (j0.type || j0.role || j0.human || j0.ai) {
    pushMsg(j0);
  }
}
if (messages.length === 0) {
  for (const it of items) pushMsg(it?.json);
}

const lines = [];
for (const m of messages) {
  const role = (m.type === 'human' || m.type === 'user') ? 'User' : 'Assistant';
  lines.push(role + ': ' + m.content);
}
const historyText = lines.join('\n');

// Most recent assistant turn's cited sources. These are the strongest
// follow-up anchor for the rewriter — if the next caller turn is a fragment
// ("what's the price?"), the rewriter is told to use these to expand it.
let priorSources = [];
for (let i = messages.length - 1; i >= 0; i--) {
  const m = messages[i];
  if ((m.type === 'ai' || m.type === 'assistant') && Array.isArray(m.sources) && m.sources.length) {
    priorSources = m.sources;
    break;
  }
}
const priorSourcesText = priorSources.length ? priorSources.join('\n') : '';

// Union of all sources cited across the entire conversation, deduplicated and
// ordered most-recent-first. The rewriter still uses `priorSources` (only the
// most recent turn) for follow-up expansion, but Fuse Retrievals uses this
// wider set so a topic-back-switch — caller spent a turn on Calacatta, now
// asks again about the original Designer Bathtub — can still anchor and pin
// the original product. Token-overlap detection in Fuse Retrievals filters
// out non-matching slugs, so widening this set is safe.
const allPriorSources = [];
const seenSrc = new Set();
for (let i = messages.length - 1; i >= 0; i--) {
  const m = messages[i];
  if ((m.type === 'ai' || m.type === 'assistant') && Array.isArray(m.sources)) {
    for (const u of m.sources) {
      if (u && !seenSrc.has(u)) { seenSrc.add(u); allPriorSources.push(u); }
    }
  }
}

const speech = $('Extract Speech Fields').first().json || {};
const ragCfg = $('RAG Config').first().json || {};

return [{
