    startedAt: speech.startedAt,
    conversationHistory: messages,
    historyText: historyText,
    historyTurnCount: messages.length,
    priorSources: priorSources,
    priorSourcesText: priorSourcesText,
    allPriorSources: allPriorSources,
    sessionSource: messages.length > 0 ? 'redis-hit' : 'first-turn'
  }
}];

