// Detect goodbye/hangup phrases up front so we don't burn an LLM call on a
// caller who's already trying to end the conversation.
const raw = ($json.transcript || '').toLowerCase().trim();

// Aggressive normalization: strip all punctuation EXCEPT apostrophe (preserves
// "that's", "we're", etc.), collapse whitespace. This lets patterns match across
// utterances like "No, no. Thank you." → "no no thank you".
const t = raw.replace(/[^a-z0-9\s']/g, ' ').replace(/\s+/g, ' ').trim();

const goodbyePatterns = [
  // "no [no...] thank you" — handles "no thank you", "no no thank you", "no, no. thank you."
  /\bno+(\s+no)*\s+thank\s*you\b/,
  /\bno\s+thanks\b/,
  /\bnope\s+thanks\b/,
  // Goodbye phrasings
  /\bgood\s*bye\b/,
  /\bbye\s+bye\b/,
  /\bthank\s*you\s+(goodbye|bye)\b/,
  // "That's all/it/fine/enough/good"
  /\bthat'?s\s+(all|it|fine|enough|good)\b/,
  /\bnothing\s+(else|more)\b/,
  /\bthat\s+(will|would)\s+be\s+all\b/,
  // "We're/I'm done/good/fine/all set"
  /\bwe'?re\s+(done|good|fine|all\s+set)\b/,
  /\bi'?m\s+(done|good|fine|all\s+set)\b/,
  // "Have a good day"
  /\bhave\s+a\s+(good|nice|great)\s+(day|night|evening|one)\b/,
  // Bare answers — entire utterance is just one of these
  /^(no|nope|nah|okay|ok|sure)$/,
  /^(thanks|thank\s*you|thank\s*you\s+so\s+much|thanks\s+a\s+lot)$/,
  // "No more questions"
  /^no\s+(more|further)\s+questions?$/,
];

let wantsToHangup = goodbyePatterns.some(p => p.test(t));

// Heuristic fallback for short polite endings the regex list might miss:
// short utterance + thanks + no actual question.
if (!wantsToHangup && t.length > 0) {
  const wordCount = t.split(/\s+/).filter(Boolean).length;
  const hasThanks = /\b(thank\s*you|thanks)\b/.test(t);
  const hasNo = /\bno\b/.test(t);
  const hasQuestionWord = /\b(do|does|did|is|are|was|were|can|could|will|would|how|what|when|where|why|which|who|tell|show|give|send|find)\b/.test(t);
  const endsWithQuestionMark = /\?\s*$/.test(raw);

  if (!hasQuestionWord && !endsWithQuestionMark) {
    if (hasThanks && wordCount <= 5) wantsToHangup = true;
    if (hasNo && hasThanks) wantsToHangup = true;
  }
}

return [{ json: { ...$json, wantsToHangup, normalizedTranscript: t } }];

